import React, { useState } from 'react';
import { getCustomerOrders } from '../firebase';
import { Order } from '../types';
import { Search, Loader2, Package, Calendar, AlertCircle, ShoppingBag, ArrowRight, Truck } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

export const OrderLookup: React.FC = () => {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');
  const [loading, setLoading] = useState(false);
  const [orders, setOrders] = useState<Order[]>([]);
  const [hasSearched, setHasSearched] = useState(false);
  const [error, setError] = useState('');

  // Normalize phone for comparison (remove spaces, dashes, etc)
  const normalizePhone = (p: string) => p.replace(/\D/g, '');

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email || !phone) {
      setError('Please provide both email and phone number for verification.');
      return;
    }

    setLoading(true);
    setError('');
    setHasSearched(false);
    setOrders([]);

    try {
      // 1. Query by Email (Public Index)
      const results = await getCustomerOrders(email);

      // 2. Client-side Security Filter by Phone
      // This ensures even if someone guesses an email, they can't see orders without the phone number.
      const searchPhoneNorm = normalizePhone(phone);

      const verifiedOrders = results.filter(order => {
        if (!order.customerPhone) return false;
        // Check if the order's phone contains the search phone or vice versa to be lenient with country codes
        const orderPhoneNorm = normalizePhone(order.customerPhone);
        return orderPhoneNorm.includes(searchPhoneNorm) || searchPhoneNorm.includes(orderPhoneNorm);
      });

      setOrders(verifiedOrders);
      setHasSearched(true);
    } catch (err) {
      console.error(err);
      setError('We could not retrieve your orders at this time. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const getStatusColor = (status: Order['status']) => {
    switch (status) {
      case 'paid': return 'bg-indigo-50 text-indigo-700 border-indigo-100';
      case 'shipped': return 'bg-blue-50 text-blue-700 border-blue-100';
      case 'delivered': return 'bg-brand-green/10 text-brand-green border-brand-green/20';
      case 'cancelled': return 'bg-gray-50 text-gray-500 border-gray-200';
      case 'failed': return 'bg-red-50 text-red-600 border-red-100';
      default: return 'bg-yellow-50 text-yellow-700 border-yellow-100';
    }
  };

  return (
    <div className="min-h-screen bg-white animate-fade-in pt-24 pb-20">
      <div className="container mx-auto px-6 max-w-4xl">

        {/* Header */}
        <div className="text-center mb-16">
          <span className="font-script text-3xl text-brand-gold mb-2 block">Concierge</span>
          <h1 className="font-serif text-3xl md:text-4xl text-gray-900 mb-6">Track Your Order</h1>
          <p className="font-sans text-gray-500 font-light max-w-md mx-auto text-sm leading-relaxed">
            Please enter the email address and phone number associated with your purchase to view your history.
          </p>
        </div>

        {/* Search Form */}
        <div className="max-w-md mx-auto bg-brand-grey/5 p-8 border border-brand-latte/20 rounded-[2px] mb-16 shadow-sm">
          <form onSubmit={handleSearch} className="flex flex-col gap-6">
            <div>
              <label className="block text-[10px] font-bold uppercase tracking-widest text-gray-400 mb-2">Email Address</label>
              <input 
                type="email" 
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="hello@example.com"
                className="w-full bg-white border border-brand-latte/30 px-4 py-3 font-sans text-gray-800 focus:outline-none focus:border-brand-flamingo focus:ring-1 focus:ring-brand-flamingo/20 transition-all placeholder:text-gray-300"
              />
            </div>
            <div>
              <label className="block text-[10px] font-bold uppercase tracking-widest text-gray-400 mb-2">Phone Number</label>
              <input 
                type="tel" 
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
                placeholder="+60..."
                className="w-full bg-white border border-brand-latte/30 px-4 py-3 font-sans text-gray-800 focus:outline-none focus:border-brand-flamingo focus:ring-1 focus:ring-brand-flamingo/20 transition-all placeholder:text-gray-300"
              />
            </div>

            {error && (
              <div className="flex items-start gap-2 text-red-500 text-xs bg-red-50 p-3 border border-red-100">
                <AlertCircle size={14} className="flex-shrink-0 mt-0.5" />
                {error}
              </div>
            )}

            <button 
              type="submit"
              disabled={loading}
              className="mt-2 bg-brand-flamingo text-white h-12 flex items-center justify-center gap-2 hover:bg-brand-gold transition-colors font-sans text-[11px] uppercase tracking-[0.2em] font-bold shadow-lg shadow-brand-flamingo/20 disabled:opacity-70"
            >
              {loading ? <Loader2 size={16} className="animate-spin" /> : <Search size={14} />}
              Find Orders
            </button>
          </form>
        </div>

        {/* Results */}
        {hasSearched && (
          <div className="animate-slide-up">
            <div className="flex items-center gap-4 mb-8">
               <div className="h-[1px] flex-1 bg-brand-latte/20"></div>
               <span className="font-serif text-xl text-gray-900">Your History</span>
               <div className="h-[1px] flex-1 bg-brand-latte/20"></div>
            </div>

            {orders.length === 0 ? (
              <div className="text-center py-12 border border-dashed border-brand-latte/30 rounded-[2px]">
                <Package size={32} className="mx-auto text-brand-latte mb-3 opacity-50" />
                <p className="text-gray-500 font-sans text-sm">No orders found matching these details.</p>
                <button onClick={() => navigate('/')} className="mt-4 text-xs font-bold text-brand-flamingo uppercase tracking-widest hover:text-brand-gold">
                  Return to Shop
                </button>
              </div>
            ) : (
              <div className="space-y-6">
                {orders.map((order) => (
                  <div key={order.id} className="bg-white border border-brand-latte/20 p-6 md:p-8 rounded-[2px] shadow-sm hover:shadow-md transition-shadow group">
                    {/* Order Header */}
                    <div className="flex flex-col md:flex-row justify-between md:items-center gap-4 mb-6 border-b border-brand-latte/10 pb-4">
                      <div>
                        <div className="flex items-center gap-3 mb-1">
                          <span className="font-mono text-sm text-gray-400">
                            {order.id.length > 8 ? `#${order.id.substring(0,6)}...` : `#${order.id}`}
                          </span>
                          <span className={`px-2 py-0.5 text-[10px] font-bold uppercase tracking-widest border rounded-full ${getStatusColor(order.status)}`}>
                            {order.status}
                          </span>
                        </div>
                        <div className="flex items-center gap-2 text-xs text-gray-500">
                          <Calendar size={12} />
                          {new Date(order.date).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })}
                        </div>
                      </div>
                      <div className="text-right">
                        <span className="block font-serif text-xl text-gray-900">RM {order.total}</span>
                        <span className="text-[10px] text-gray-400 uppercase tracking-widest">Total Paid</span>
                      </div>
                    </div>

                    {/* Items */}
                    <div className="flex flex-col gap-4">
                      {order.items.map((item, idx) => (
                        <div key={idx} className="flex gap-4 items-center">
                          <div className="w-12 h-16 bg-brand-grey/10 overflow-hidden rounded-[2px] border border-brand-latte/10">
                             <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                          </div>
                          <div className="flex-1">
                            <h4 className="font-serif text-gray-900 text-sm">{item.name}</h4>
                            <p className="text-xs text-gray-500">Qty: {item.quantity}</p>
                          </div>
                          <div className="text-sm font-bold text-gray-900">RM {item.price}</div>
                        </div>
                      ))}
                    </div>

                    {/* Footer Actions */}
                    <div className="mt-6 pt-6 border-t border-brand-latte/10 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                      <div className="flex items-center gap-2 text-xs text-gray-500">
                        <Truck size={14} />
                        <span className="truncate max-w-xs">{order.shippingAddress}</span>
                      </div>

                      {/* Only show 'Buy Again' if not cancelled/failed */}
                      {order.status !== 'cancelled' && order.status !== 'failed' && (
                         <button 
                           onClick={() => navigate(`/product/${order.items[0].id}`)}
                           className="text-brand-flamingo text-[10px] font-bold uppercase tracking-widest flex items-center gap-1 hover:gap-2 transition-all"
                         >
                           View Item <ArrowRight size={12} />
                         </button>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { CheckCircle, XCircle, ArrowRight, Loader2, AlertCircle } from 'lucide-react';
import { updateOrderStatusInDb } from '../firebase';

export const PaymentCallback: React.FC = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const [status, setStatus] = useState<'loading' | 'success' | 'failed' | 'cancelled'>('loading');
  const [displayOrderId, setDisplayOrderId] = useState<string>('');

  useEffect(() => {
    const result = searchParams.get('result');
    const orderId = searchParams.get('order');

    if (orderId) setDisplayOrderId(orderId);

    const handleCallback = async () => {
      if (!orderId) {
        setStatus('failed');
        return;
      }

      try {
        if (result === 'success') {
          await updateOrderStatusInDb(orderId, 'paid');
          setStatus('success');
        } else if (result === 'failed') {
          await updateOrderStatusInDb(orderId, 'failed');
          setStatus('failed');
        } else if (result === 'cancelled') {
          await updateOrderStatusInDb(orderId, 'cancelled');
          setStatus('cancelled');
        } else {
          setStatus('failed');
        }
      } catch (error) {
        console.error("Failed to update order status:", error);
        // Fallback UI based on result parameter if DB update fails
        if (result === 'success') setStatus('success');
        else if (result === 'cancelled') setStatus('cancelled');
        else setStatus('failed');
      }
    };

    // Small delay to ensure smooth transition
    const timer = setTimeout(() => {
      handleCallback();
    }, 1000);

    return () => clearTimeout(timer);
  }, [searchParams]);

  return (
    <div className="min-h-screen bg-white flex items-center justify-center p-6 animate-fade-in">
      <div className="max-w-md w-full text-center">

        {status === 'loading' && (
          <div className="flex flex-col items-center">
             <Loader2 size={48} className="text-brand-gold animate-spin mb-6" />
             <h2 className="font-serif text-2xl text-gray-900">Processing...</h2>
             <p className="text-gray-400 text-xs mt-2">Updating your order status</p>
          </div>
        )}

        {status === 'success' && (
          <div className="flex flex-col items-center animate-slide-up">
            <div className="w-20 h-20 bg-green-50 rounded-full flex items-center justify-center mb-6">
              <CheckCircle size={40} className="text-brand-green" />
            </div>
            <h1 className="font-serif text-3xl md:text-4xl text-gray-900 mb-2">Payment Successful</h1>
            {displayOrderId && (
              <div className="mb-4 bg-brand-grey/10 px-4 py-1 rounded-full text-xs font-mono text-gray-500">
                Order #{displayOrderId}
              </div>
            )}
            <p className="font-sans text-gray-500 mb-8 leading-relaxed">
              Thank you for your purchase. Your order has been confirmed. A receipt has been sent to your email.
            </p>
            <button 
              onClick={() => navigate('/')}
              className="bg-brand-flamingo text-white px-8 py-3.5 font-sans uppercase tracking-[0.2em] text-[10px] font-bold hover:bg-brand-gold transition-colors rounded-full flex items-center gap-2"
            >
              Continue Shopping <ArrowRight size={14} />
            </button>
          </div>
        )}

        {status === 'failed' && (
          <div className="flex flex-col items-center animate-slide-up">
            <div className="w-20 h-20 bg-red-50 rounded-full flex items-center justify-center mb-6">
              <XCircle size={40} className="text-red-400" />
            </div>
            <h1 className="font-serif text-3xl md:text-4xl text-gray-900 mb-4">Payment Failed</h1>
            <p className="font-sans text-gray-500 mb-8 leading-relaxed">
              We couldn't process your payment. Please try again or use a different payment method.
            </p>
            <div className="flex gap-4">
              <button 
                onClick={() => navigate('/checkout')}
                className="bg-gray-900 text-white px-8 py-3.5 font-sans uppercase tracking-[0.2em] text-[10px] font-bold hover:bg-brand-flamingo transition-colors rounded-full"
              >
                Try Again
              </button>
              <button 
                onClick={() => navigate('/')}
                className="text-gray-500 px-6 py-3.5 font-sans uppercase tracking-[0.2em] text-[10px] font-bold hover:text-gray-900 transition-colors"
              >
                Return Home
              </button>
            </div>
          </div>
        )}

        {status === 'cancelled' && (
          <div className="flex flex-col items-center animate-slide-up">
            <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mb-6">
              <AlertCircle size={40} className="text-gray-400" />
            </div>
            <h1 className="font-serif text-3xl md:text-4xl text-gray-900 mb-4">Payment Cancelled</h1>
            <p className="font-sans text-gray-500 mb-8 leading-relaxed">
              You have cancelled the payment process. Your items are still in your bag.
            </p>
            <div className="flex gap-4">
              <button 
                onClick={() => navigate('/checkout')}
                className="bg-brand-gold text-white px-8 py-3.5 font-sans uppercase tracking-[0.2em] text-[10px] font-bold hover:bg-brand-flamingo transition-colors rounded-full"
              >
                Return to Checkout
              </button>
            </div>
          </div>
        )}

      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { CartItem } from '../types';
import { Lock, CheckCircle, ArrowLeft, Loader2, CreditCard, AlertTriangle, Phone, Tag, X } from 'lucide-react';
import { createOrderInDb } from '../firebase';
import { useNavigate } from 'react-router-dom';

interface CheckoutViewProps {
  cart: CartItem[];
  onOrderSuccess: () => void;
}

// We use the local proxy path now (configured in vite.config.ts and vercel.json)
// This avoids CORS errors by letting the server handle the cross-origin request
const API_URL = '/api/chip/purchases/';

export const CheckoutView: React.FC<CheckoutViewProps> = ({ cart, onOrderSuccess }) => {
  const navigate = useNavigate();
  const subtotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalItems = cart.reduce((sum, item) => sum + item.quantity, 0);

  // Shipping State
  const [region, setRegion] = useState<'west' | 'east'>('west');

  // Voucher State
  const [voucherCode, setVoucherCode] = useState('');
  const [isFreeShipping, setIsFreeShipping] = useState(false);
  const [voucherMessage, setVoucherMessage] = useState<{type: 'success' | 'error', text: string} | null>(null);

  // Shipping Logic
  // West Malaysia: RM 8 flat, or RM 10 if 3+ items
  // East Malaysia: RM 12 flat
  const calculateShipping = () => {
    if (isFreeShipping) return 0;

    if (region === 'east') {
      return 12;
    } else {
      return totalItems >= 3 ? 10 : 8;
    }
  };

  const shipping = calculateShipping();
  const total = subtotal + shipping;

  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState('');

  // Form State
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [address, setAddress] = useState('');
  const [postcode, setPostcode] = useState('');
  const [city, setCity] = useState('');

  // Access Environment Variables Directly
  // Note: We access them directly on import.meta.env so Vite can statically replace them at build time.
  const getPaymentConfig = () => {
    const env = (import.meta as any).env;
    return {
      // Try VITE_ prefix first (Standard), then CHIP_ prefix
      brandId: env.VITE_CHIP_ID || env.CHIP_ID,
      apiKey: env.VITE_CHIP_API || env.CHIP_API
    };
  };

  // Debugging: Check if keys are loaded
  useEffect(() => {
    const { brandId, apiKey } = getPaymentConfig();
    const isConfigured = !!brandId && !!apiKey;

    console.log(`[Payment Config] Loaded: ${isConfigured}`);

    if (!isConfigured) {
      console.warn("[Payment Config] Missing keys. Ensure VITE_CHIP_ID and VITE_CHIP_API are set in Vercel and you have REDEPLOYED.");
    }
  }, []);

  const handleApplyVoucher = (e: React.MouseEvent) => {
    e.preventDefault();
    setVoucherMessage(null);

    const code = voucherCode.trim().toUpperCase();

    if (!code) return;

    if (code === 'SHIPFREE88') {
      setIsFreeShipping(true);
      setVoucherMessage({ type: 'success', text: 'Free shipping applied!' });
    } else {
      setIsFreeShipping(false);
      setVoucherMessage({ type: 'error', text: 'Invalid voucher code.' });
    }
  };

  const handleRemoveVoucher = () => {
    setVoucherCode('');
    setIsFreeShipping(false);
    setVoucherMessage(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);
    setError('');

    const { brandId, apiKey } = getPaymentConfig();

    if (!brandId || !apiKey) {
      setError("Configuration Error: Payment Gateway ID or API Key is missing.");
      setIsProcessing(false);
      return;
    }

    try {
      // 1. Create Order in Database first (status pending)
      const orderRef = await createOrderInDb({
        customerName: `${firstName} ${lastName}`,
        customerEmail: email,
        customerPhone: phone,
        items: cart,
        total: total,
        status: 'pending',
        date: new Date().toISOString(),
        shippingAddress: `${address}, ${postcode} ${city}, ${region === 'east' ? 'East Malaysia' : 'West Malaysia'}`
      });

      // 2. Prepare Chip Payload
      // Note: Amounts must be in cents (integer)
      const payload = {
        brand_id: brandId,
        client: {
          email: email,
          phone: phone, 
          full_name: `${firstName} ${lastName}`.substring(0, 30), // Chip limit
        },
        purchase: {
          currency: 'MYR',
          products: [
            ...cart.map(item => ({
              name: item.name.substring(0, 256),
              quantity: item.quantity,
              price: Math.round(item.price * 100) // Chip expects cents
            })),
            {
              name: isFreeShipping ? "Shipping Fee (Waived)" : "Shipping Fee",
              quantity: 1,
              price: Math.round(shipping * 100)
            }
          ]
        },
        reference: orderRef.id,
        // We pass the order ID in the redirect URL so we can update it later
        success_redirect: `${window.location.origin}/#/payment/callback?result=success&order=${orderRef.id}`,
        failure_redirect: `${window.location.origin}/#/payment/callback?result=failed&order=${orderRef.id}`,
        // Redirect cancel to callback too, so we can mark it as 'cancelled' in DB
        cancel_redirect: `${window.location.origin}/#/payment/callback?result=cancelled&order=${orderRef.id}`,
      };

      // 3. Call Chip API via Proxy
      const response = await fetch(API_URL, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiKey}`
        },
        body: JSON.stringify(payload)
      });

      let data;
      try {
        data = await response.json();
      } catch (jsonError) {
        throw new Error(`Invalid response from payment provider: ${response.statusText}`);
      }

      if (!response.ok) {
        console.error("Chip API Error Response:", data);
        const msg = data.message || (data.errors ? Object.values(data.errors).join(', ') : "Payment initialization failed");
        throw new Error(msg);
      }

      onOrderSuccess(); 

      if (data.checkout_url) {
        window.location.href = data.checkout_url;
      } else {
        throw new Error("No checkout URL returned from payment provider");
      }

    } catch (err: any) {
      console.error("Payment Error:", err);
      setError(err.message || "Failed to initiate payment. Please try again.");
      setIsProcessing(false);
    }
  };

  return (
    <div className="min-h-screen bg-white animate-fade-in flex flex-col lg:flex-row">

      {/* Left Column: Form */}
      <div className="w-full lg:w-[58%] px-6 lg:px-24 pt-12 lg:pt-24 pb-12 border-r border-brand-latte/10">
        <div className="max-w-xl mx-auto lg:mx-0">

          <button onClick={() => navigate('/cart')} className="flex items-center gap-2 text-gray-400 hover:text-brand-flamingo mb-10 transition-colors text-xs font-bold uppercase tracking-widest">
            <ArrowLeft size={14} /> Back to Bag
          </button>

          <div className="mb-12">
            <h1 className="font-serif text-3xl text-gray-900 mb-2">Checkout</h1>
            <p className="font-sans text-gray-400 text-sm">Please enter your details below.</p>
          </div>

          <form onSubmit={handleSubmit} className="flex flex-col gap-10">

            {/* Contact */}
            <section>
              <h2 className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 mb-6">Contact Information</h2>
              <div className="flex flex-col gap-6">
                <input 
                  type="email" 
                  placeholder="Email Address" 
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors"
                />
                <input 
                  type="tel" 
                  placeholder="Phone Number (e.g. +60123456789)" 
                  required
                  value={phone}
                  onChange={(e) => setPhone(e.target.value)}
                  className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors"
                />
              </div>
            </section>

            {/* Shipping */}
            <section>
              <h2 className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 mb-6">Shipping Address</h2>
              <div className="grid grid-cols-2 gap-6 mb-6">
                <input 
                  type="text" placeholder="First Name" required 
                  value={firstName} onChange={e => setFirstName(e.target.value)}
                  className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                />
                <input 
                  type="text" placeholder="Last Name" required 
                  value={lastName} onChange={e => setLastName(e.target.value)}
                  className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                />
              </div>
              <div className="flex flex-col gap-6">
                <input 
                  type="text" placeholder="Address" required 
                  value={address} onChange={e => setAddress(e.target.value)}
                  className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                />
                <input type="text" placeholder="Apartment, suite, etc. (optional)" className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" />
                <div className="grid grid-cols-2 gap-6">
                   <input 
                    type="text" placeholder="Postcode" required 
                    value={postcode} onChange={e => setPostcode(e.target.value)}
                    className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                   />
                   <input 
                    type="text" placeholder="City" required 
                    value={city} onChange={e => setCity(e.target.value)}
                    className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                   />
                </div>

                {/* Region Selection for Shipping Calc */}
                <div className="relative">
                  <select 
                    value={region}
                    onChange={(e) => setRegion(e.target.value as 'west' | 'east')}
                    className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 transition-colors appearance-none cursor-pointer"
                  >
                    <option value="west">West Malaysia (Peninsular)</option>
                    <option value="east">East Malaysia (Sabah & Sarawak)</option>
                  </select>
                  <div className="absolute right-0 top-1/2 -translate-y-1/2 pointer-events-none opacity-50">
                    <svg width="10" height="6" viewBox="0 0 10 6" fill="currentColor">
                       <path d="M5 6L0 0H10L5 6Z" />
                    </svg>
                  </div>
                </div>

                <input type="text" placeholder="Country" defaultValue="Malaysia" disabled className="w-full py-3 bg-transparent border-b border-brand-latte/40 text-gray-400 cursor-not-allowed font-sans" />
              </div>
            </section>

            {/* Voucher Section */}
            <section>
              <h2 className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 mb-6 flex items-center gap-2">
                 <Tag size={14} className="text-gray-400" /> Voucher
              </h2>

              <div className="relative">
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    placeholder="Enter voucher code" 
                    value={voucherCode}
                    onChange={(e) => setVoucherCode(e.target.value)}
                    disabled={isFreeShipping}
                    className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed" 
                  />
                  {isFreeShipping ? (
                    <button 
                      type="button" 
                      onClick={handleRemoveVoucher}
                      className="text-gray-400 hover:text-red-400 transition-colors px-4 border-b border-brand-latte/40"
                    >
                      <X size={18} />
                    </button>
                  ) : (
                    <button 
                      type="button" 
                      onClick={handleApplyVoucher}
                      className="bg-gray-900 text-white px-6 py-2 text-[10px] font-bold uppercase tracking-widest hover:bg-brand-flamingo transition-colors rounded-[2px]"
                    >
                      Apply
                    </button>
                  )}
                </div>

                {voucherMessage && (
                  <p className={`text-xs mt-2 flex items-center gap-1 ${voucherMessage.type === 'success' ? 'text-green-600' : 'text-red-500'}`}>
                    {voucherMessage.type === 'success' ? <CheckCircle size={12} /> : <AlertTriangle size={12} />}
                    {voucherMessage.text}
                  </p>
                )}
              </div>
            </section>

            {/* Payment Info */}
            <section>
              <h2 className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 mb-6">Payment Method</h2>
              <div className="bg-brand-grey/5 p-6 rounded-[2px] border border-brand-latte/10">
                <div className="flex flex-col gap-4 items-center justify-center py-4 text-center">
                  <Lock size={24} className="text-brand-latte mb-2" />
                  <p className="text-sm text-gray-500 font-light">
                    You will be redirected to <span className="font-bold text-gray-900">CHIP</span> to securely complete your payment.
                  </p>
                  <div className="flex items-center gap-2 text-[10px] text-gray-400 uppercase tracking-widest mt-2">
                    <CreditCard size={12} /> Secure Gateway
                  </div>
                </div>
              </div>
            </section>

            {error && (
              <div className="bg-red-50 p-4 rounded border border-red-100 flex items-start gap-3">
                <AlertTriangle className="text-red-500 flex-shrink-0 mt-0.5" size={16} />
                <div className="flex-1">
                  <p className="text-red-600 text-sm font-bold mb-1">Payment Initialization Failed</p>
                  <p className="text-red-500 text-xs">{error}</p>
                  {(error.includes("Configuration") || error.includes("missing")) && (
                     <p className="text-red-500 text-[10px] mt-2 italic">
                       Developer Note: Ensure VITE_CHIP_ID and VITE_CHIP_API are set in Vercel and the app has been redeployed.
                     </p>
                  )}
                </div>
              </div>
            )}

            <button 
                type="submit"
                disabled={isProcessing}
                className="mt-4 w-full bg-brand-flamingo text-white h-14 rounded-full flex items-center justify-center gap-3 hover:bg-brand-gold transition-colors font-sans text-[11px] uppercase tracking-[0.2em] font-bold shadow-lg shadow-brand-flamingo/20 disabled:opacity-70 disabled:cursor-wait"
              >
                {isProcessing ? (
                  <>
                    <Loader2 size={16} className="animate-spin" /> Redirecting to CHIP...
                  </>
                ) : (
                  `Pay RM ${total}`
                )}
            </button>

          </form>
        </div>
      </div>

      {/* Right Column: Summary */}
      <div className="w-full lg:w-[42%] bg-brand-grey/5 px-6 lg:px-16 pt-12 lg:pt-24 pb-12 lg:min-h-screen border-l border-brand-latte/10">
        <div className="max-w-md mx-auto lg:mx-0 sticky top-24">
          <h2 className="font-serif text-2xl text-gray-900 mb-8">In Your Bag</h2>

          <div className="space-y-6 mb-10">
            {cart.map(item => (
              <div key={item.id} className="flex gap-4 items-start">
                 <div className="w-16 h-20 bg-white border border-brand-latte/20 relative rounded-[2px] overflow-hidden">
                    <img src={item.image} className="w-full h-full object-cover" />
                    <span className="absolute -top-0 -right-0 w-5 h-5 bg-brand-latte/90 text-white text-[10px] font-bold flex items-center justify-center rounded-bl-lg">
                      {item.quantity}
                    </span>
                 </div>
                 <div className="flex-1">
                   <h4 className="font-serif text-gray-900">{item.name}</h4>
                   <p className="text-xs text-gray-500 font-sans mt-1">RM {item.price}</p>
                 </div>
                 <div className="font-sans text-sm font-bold text-gray-900">
                   RM {item.price * item.quantity}
                 </div>
              </div>
            ))}
          </div>

          <div className="border-t border-brand-latte/20 pt-6 space-y-3">
             <div className="flex justify-between text-sm font-sans text-gray-600">
                <span>Subtotal</span>
                <span>RM {subtotal}</span>
             </div>
             <div className="flex justify-between text-sm font-sans text-gray-600 items-center">
                <span>Shipping</span>
                {isFreeShipping ? (
                  <span className="text-brand-green font-bold text-xs uppercase tracking-wider flex items-center gap-1">
                    <Tag size={10} /> Free
                  </span>
                ) : (
                  <span>RM {shipping}</span>
                )}
             </div>

             {/* Shipping Note */}
             {!isFreeShipping && (
               <div className="text-[10px] text-gray-400 italic text-right">
                 {region === 'west' 
                   ? (totalItems >= 3 ? '(West Malaysia Bulk Rate)' : '(West Malaysia Standard Rate)') 
                   : '(East Malaysia Rate)'}
               </div>
             )}

             {/* Applied Voucher Note */}
             {isFreeShipping && (
                <div className="text-[10px] text-brand-green italic text-right">
                  Code SHIPFREE88 applied
                </div>
             )}
          </div>

          <div className="border-t border-brand-latte/20 pt-6 mt-6">
             <div className="flex justify-between items-end">
                <span className="font-serif text-xl text-gray-900">Total</span>
                <span className="font-serif text-3xl text-gray-900">RM {total}</span>
             </div>
          </div>

          <div className="mt-12 flex items-center gap-3 justify-center text-brand-gold opacity-60">
             <CheckCircle size={14} />
             <span className="text-[10px] uppercase tracking-widest font-bold">Secure Payment Processing</span>
          </div>

        </div>
      </div>

    </div>
  );
};

