      return `ORDER #${o.id}
Date: ${new Date(o.date).toLocaleDateString()}
Customer: ${o.customerName}
Phone: ${o.customerPhone}
Address: ${o.shippingAddress}
Items:
${o.items.map(i => `- ${i.quantity}x ${i.name}`).join('\n')}
--------------------------------`;
