import React, { useState, useEffect } from 'react';
import { Product } from '../types';
import { ArrowLeft, Minus, Plus, ShoppingBag, Truck, Info, Leaf, Loader2, Check, AlertCircle, Ruler } from 'lucide-react';
import { useParams, useNavigate } from 'react-router-dom';

interface ProductDetailsProps {
  products: Product[];
  onAddToCart: (product: Product, quantity: number) => void;
}

const AccordionItem: React.FC<{ title: string; children: React.ReactNode; isOpen: boolean; toggle: () => void }> = ({ title, children, isOpen, toggle }) => (
  <div className="border-b border-brand-latte/20">
    <button onClick={toggle} className="w-full py-4 flex items-center justify-between text-left group">
      <span className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 group-hover:text-brand-flamingo transition-colors">{title}</span>
      {isOpen ? <Minus size={14} className="text-brand-flamingo" /> : <Plus size={14} className="text-gray-400" />}
    </button>
    <div className={`overflow-hidden transition-all duration-500 ease-in-out ${isOpen ? 'max-h-96 opacity-100 mb-6' : 'max-h-0 opacity-0'}`}>
      <div className="font-sans text-sm text-gray-500 leading-relaxed font-light">
        {children}
      </div>
    </div>
  </div>
);

export const ProductDetails: React.FC<ProductDetailsProps> = ({ products, onAddToCart }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [product, setProduct] = useState<Product | undefined>(undefined);
  const [loading, setLoading] = useState(true);
  const [activeImage, setActiveImage] = useState<string>('');

  const [openSection, setOpenSection] = useState<string>('material');
  const [quantity, setQuantity] = useState(1);
  const [addState, setAddState] = useState<'idle' | 'loading' | 'success'>('idle');

  useEffect(() => {
    // In a real app we might fetch from DB here if not in list
    if (products.length > 0) {
      const found = products.find(p => p.id === id);
      setProduct(found);
      if (found) setActiveImage(found.image);
      setLoading(false);
    } else {
      // Allow time for products to load from Firebase
      const timer = setTimeout(() => setLoading(false), 2000);
      return () => clearTimeout(timer);
    }
  }, [id, products]);

  const toggleSection = (section: string) => {
    setOpenSection(openSection === section ? '' : section);
  };

  const handleAddToCart = () => {
    if (addState !== 'idle' || !product) return;
    setAddState('loading');

    setTimeout(() => {
      onAddToCart(product, quantity);
      setAddState('success');
      setTimeout(() => {
        setAddState('idle');
      }, 2000);
    }, 600);
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center pt-24">
        <Loader2 className="animate-spin text-brand-latte" />
      </div>
    );
  }

  if (!product) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center pt-24 pb-12">
        <AlertCircle size={48} className="text-brand-latte mb-4 opacity-50" />
        <h2 className="font-serif text-2xl text-gray-900 mb-2">Product Not Found</h2>
        <p className="text-gray-500 mb-6">The item you are looking for does not exist.</p>
        <button onClick={() => navigate('/')} className="text-xs font-bold uppercase tracking-widest text-brand-flamingo hover:text-brand-gold">
          Return to Shop
        </button>
      </div>
    );
  }

  const galleryImages = [product.image, ...(product.additionalImages || [])];

  return (
    <div className="min-h-screen bg-white animate-fade-in pt-24 pb-12">
      <div className="container mx-auto px-6 max-w-6xl">

        {/* Breadcrumb / Back */}
        <button onClick={() => navigate('/')} className="flex items-center gap-2 text-gray-400 hover:text-brand-flamingo mb-8 transition-colors group">
          <ArrowLeft size={16} className="group-hover:-translate-x-1 transition-transform" />
          <span className="font-sans text-[10px] uppercase tracking-widest font-bold">Back to Shop</span>
        </button>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 lg:gap-24">

          {/* Left: Imagery */}
          <div className="flex flex-col gap-6">
            <div className="relative aspect-[3/4] bg-brand-grey/5 rounded-[2px] overflow-hidden group border border-brand-latte/10">
               <img 
                 src={activeImage || product.image} 
                 alt={product.name} 
                 className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
               />
            </div>
            {/* Gallery Thumbnails */}
            {galleryImages.length > 1 && (
              <div className="grid grid-cols-4 gap-4">
                 {galleryImages.map((img, i) => (
                   <div 
                     key={i} 
                     onClick={() => setActiveImage(img)}
                     className={`aspect-square bg-brand-grey/10 cursor-pointer overflow-hidden rounded-[2px] border transition-all duration-300 ${
                       activeImage === img ? 'border-brand-flamingo ring-1 ring-brand-flamingo/50' : 'border-transparent hover:border-brand-latte'
                     }`}
                   >
                     <img 
                       src={img} 
                       className={`w-full h-full object-cover transition-opacity duration-300 ${activeImage === img ? 'opacity-100' : 'opacity-70 hover:opacity-100'}`} 
                       alt={`${product.name} view ${i + 1}`}
                     />
                   </div>
                 ))}
              </div>
            )}
          </div>

          {/* Right: Details */}
          <div className="flex flex-col pt-4">
            <h1 className="font-serif text-3xl md:text-4xl text-gray-900 mb-4">{product.name}</h1>

            <div className="flex items-center gap-4 mb-8">
              <span className="font-serif text-2xl text-gray-900">RM {product.price}</span>
              <div className="h-4 w-[1px] bg-gray-200"></div>
              <span className="font-script text-xl text-brand-gold">
                {(!product.collection || product.collection === 'Blankets') ? 'Blanket Collection' : product.collection}
              </span>
            </div>

            <p className="font-serif italic text-gray-600 text-base leading-relaxed mb-8 border-l-2 border-brand-flamingo pl-6">
              "{product.description}"
            </p>

            {/* Actions */}
            <div className="flex flex-col sm:flex-row gap-4 mb-12">
               <div className="flex items-center border border-brand-latte/30 rounded-full h-12 w-full sm:w-32 px-4 justify-between">
                 <button onClick={() => setQuantity(Math.max(1, quantity - 1))} className="text-gray-400 hover:text-brand-flamingo"><Minus size={14}/></button>
                 <span className="font-sans font-bold text-sm text-gray-900">{quantity}</span>
                 <button onClick={() => setQuantity(quantity + 1)} className="text-gray-400 hover:text-brand-flamingo"><Plus size={14}/></button>
               </div>

               <button 
                 onClick={handleAddToCart}
                 disabled={addState !== 'idle'}
                 className={`w-full sm:flex-1 h-12 rounded-full flex items-center justify-center gap-3 transition-all duration-300 font-sans text-[11px] uppercase tracking-[0.2em] font-bold shadow-lg 
                   ${addState === 'success' 
                      ? 'bg-brand-green text-white hover:bg-brand-green/90 shadow-brand-green/20' 
                      : 'bg-brand-flamingo text-white hover:bg-brand-gold shadow-brand-flamingo/20'
                   }`}
                >
                 {addState === 'loading' ? (
                   <Loader2 size={16} className="animate-spin" />
                 ) : addState === 'success' ? (
                   <>
                     <Check size={16} />
                     Added
                   </>
                 ) : (
                   <>
                     <ShoppingBag size={16} strokeWidth={1.5} />
                     Add to Bag
                   </>
                 )}
               </button>
            </div>

            {/* Info Accordions */}
            <div className="mt-auto">
              <AccordionItem 
                title="Material & Composition" 
                isOpen={openSection === 'material'} 
                toggle={() => toggleSection('material')}
              >
                <div className="flex items-start gap-3">
                   <Leaf size={16} className="text-brand-latte mt-1 flex-shrink-0" />
                   <p>{product.material || 'Premium ethically sourced fibers.'}</p>
                </div>
              </AccordionItem>

              <AccordionItem 
                title="Dimensions" 
                isOpen={openSection === 'size'} 
                toggle={() => toggleSection('size')}
              >
                <div className="flex items-start gap-3">
                   <Ruler size={16} className="text-brand-latte mt-1 flex-shrink-0" />
                   <p>{product.size || 'One size fits most.'}</p>
                </div>
              </AccordionItem>

              <AccordionItem 
                title="Care Instructions" 
                isOpen={openSection === 'care'} 
                toggle={() => toggleSection('care')}
              >
                <div className="flex items-start gap-3">
                   <Info size={16} className="text-brand-latte mt-1 flex-shrink-0" />
                   <p>{product.care || 'Gentle hand wash recommended to preserve the softness of the fibers.'}</p>
                </div>
              </AccordionItem>

              <AccordionItem 
                title="Shipping & Returns" 
                isOpen={openSection === 'shipping'} 
                toggle={() => toggleSection('shipping')}
              >
                 <div className="flex items-start gap-3">
                   <Truck size={16} className="text-brand-latte mt-1 flex-shrink-0" />
                   <div className="flex flex-col gap-3">
                     <p>Delivery to West Malaysia is available at a flat rate of RM 8.00. For larger orders containing three (3) or more items, a standard shipping fee of RM 10.00 applies. </p>
                     <p>Shipping to East Malaysia (Sabah & Sarawak) is charged at RM 12.00.</p>
                     <p className="italic text-brand-gold">Please kindly note that all sales are final. We are unable to accept returns or exchanges.</p>
                   </div>
                </div>
              </AccordionItem>
            </div>

          </div>
        </div>
      </div>
    </div>
  );
};

{
  "name": "once-upon-story",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "tsc && vite build",
    "preview": "vite preview"
  },
  "dependencies": {
    "firebase": "^10.8.1",
    "lucide-react": "^0.344.0",
    "react": "^18.2.0",
    "react-dom": "^18.2.0",
    "react-router-dom": "^6.22.3"
  },
  "devDependencies": {
    "@types/react": "^18.2.0",
    "@types/react-dom": "^18.2.0",
    "@vitejs/plugin-react": "^4.2.1",
    "typescript": "^5.2.2",
    "vite": "^5.1.4"
  }
}

import React, { useState, useEffect } from 'react';
import { CartItem } from '../types';
import { Lock, CheckCircle, ArrowLeft, Loader2, CreditCard, AlertTriangle, Phone, Tag, X, Gift, Feather, Sparkles } from 'lucide-react';
import { createOrderInDb } from '../firebase';
import { useNavigate } from 'react-router-dom';

interface CheckoutViewProps {
  cart: CartItem[];
  onOrderSuccess: () => void;
}

// We use the local proxy path now (configured in vite.config.ts and vercel.json)
// This avoids CORS errors by letting the server handle the cross-origin request
const API_URL = '/api/chip/purchases/';

export const CheckoutView: React.FC<CheckoutViewProps> = ({ cart, onOrderSuccess }) => {
  const navigate = useNavigate();
  const subtotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalItems = cart.reduce((sum, item) => sum + item.quantity, 0);

  // Shipping State
  const [region, setRegion] = useState<'west' | 'east'>('west');

  // Voucher State
  const [voucherCode, setVoucherCode] = useState('');
  const [isFreeShipping, setIsFreeShipping] = useState(false);
  const [voucherMessage, setVoucherMessage] = useState<{type: 'success' | 'error', text: string} | null>(null);

  // Shipping Logic
  // West Malaysia: RM 8 flat, or RM 10 if 3+ items
  // East Malaysia: RM 12 flat
  const calculateShipping = () => {
    if (isFreeShipping) return 0;

    if (region === 'east') {
      return 12;
    } else {
      return totalItems >= 3 ? 10 : 8;
    }
  };

  const shipping = calculateShipping();
  const total = subtotal + shipping;

  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState('');

  // Form State
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [address, setAddress] = useState('');
  const [postcode, setPostcode] = useState('');
  const [city, setCity] = useState('');

  // Access Environment Variables Directly
  // Note: We access them directly on import.meta.env so Vite can statically replace them at build time.
  const getPaymentConfig = () => {
    const env = (import.meta as any).env;
    return {
      // Try VITE_ prefix first (Standard), then CHIP_ prefix
      brandId: env.VITE_CHIP_ID || env.CHIP_ID,
      apiKey: env.VITE_CHIP_API || env.CHIP_API
    };
  };

  // Debugging: Check if keys are loaded
  useEffect(() => {
    const { brandId, apiKey } = getPaymentConfig();
    const isConfigured = !!brandId && !!apiKey;

    console.log(`[Payment Config] Loaded: ${isConfigured}`);

    if (!isConfigured) {
      console.warn("[Payment Config] Missing keys. Ensure VITE_CHIP_ID and VITE_CHIP_API are set in Vercel and you have REDEPLOYED.");
    }
  }, []);

  const handleApplyVoucher = (e: React.MouseEvent) => {
    e.preventDefault();
    setVoucherMessage(null);

    const code = voucherCode.trim().toUpperCase();

    if (!code) return;

    if (code === 'SHIPFREE88') {
      setIsFreeShipping(true);
      setVoucherMessage({ type: 'success', text: 'Free shipping applied!' });
    } else {
      setIsFreeShipping(false);
      setVoucherMessage({ type: 'error', text: 'Invalid voucher code.' });
    }
  };

  const handleRemoveVoucher = () => {
    setVoucherCode('');
    setIsFreeShipping(false);
    setVoucherMessage(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);
    setError('');

    const { brandId, apiKey } = getPaymentConfig();

    if (!brandId || !apiKey) {
      setError("Configuration Error: Payment Gateway ID or API Key is missing.");
      setIsProcessing(false);
      return;
    }

    try {
      // 1. Create Order in Database first (status pending)
      const orderRef = await createOrderInDb({
        customerName: `${firstName} ${lastName}`,
        customerEmail: email,
        customerPhone: phone,
        items: cart,
        total: total,
        status: 'pending',
        date: new Date().toISOString(),
        shippingAddress: `${address}, ${postcode} ${city}, ${region === 'east' ? 'East Malaysia' : 'West Malaysia'}`
      });

      // 2. Prepare Chip Payload
      // Note: Amounts must be in cents (integer)
      const payload = {
        brand_id: brandId,
        client: {
          email: email,
          phone: phone, 
          full_name: `${firstName} ${lastName}`.substring(0, 30), // Chip limit
        },
        purchase: {
          currency: 'MYR',
          products: [
            ...cart.map(item => ({
              name: item.name.substring(0, 256),
              quantity: item.quantity,
              price: Math.round(item.price * 100) // Chip expects cents
            })),
            {
              name: isFreeShipping ? "Shipping Fee (Waived)" : "Shipping Fee",
              quantity: 1,
              price: Math.round(shipping * 100)
            }
          ]
        },
        reference: orderRef.id,
        // We pass the order ID in the redirect URL so we can update it later
        success_redirect: `${window.location.origin}/#/payment/callback?result=success&order=${orderRef.id}`,
        failure_redirect: `${window.location.origin}/#/payment/callback?result=failed&order=${orderRef.id}`,
        // Redirect cancel to callback too, so we can mark it as 'cancelled' in DB
        cancel_redirect: `${window.location.origin}/#/payment/callback?result=cancelled&order=${orderRef.id}`,
      };

      // 3. Call Chip API via Proxy
      const response = await fetch(API_URL, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiKey}`
        },
        body: JSON.stringify(payload)
      });

      let data;
      try {
        data = await response.json();
      } catch (jsonError) {
        throw new Error(`Invalid response from payment provider: ${response.statusText}`);
      }

      if (!response.ok) {
        console.error("Chip API Error Response:", data);
        const msg = data.message || (data.errors ? Object.values(data.errors).join(', ') : "Payment initialization failed");
        throw new Error(msg);
      }

      onOrderSuccess(); 

      if (data.checkout_url) {
        window.location.href = data.checkout_url;
      } else {
        throw new Error("No checkout URL returned from payment provider");
      }

    } catch (err: any) {
      console.error("Payment Error:", err);
      setError(err.message || "Failed to initiate payment. Please try again.");
      setIsProcessing(false);
    }
  };

  return (
    <div className="min-h-screen bg-white animate-fade-in flex flex-col lg:flex-row">

      {/* Left Column: Form */}
      <div className="w-full lg:w-[58%] px-6 lg:px-24 pt-12 lg:pt-24 pb-12 border-r border-brand-latte/10">
        <div className="max-w-xl mx-auto lg:mx-0">

          <button onClick={() => navigate('/cart')} className="flex items-center gap-2 text-gray-400 hover:text-brand-flamingo mb-10 transition-colors text-xs font-bold uppercase tracking-widest">
            <ArrowLeft size={14} /> Back to Bag
          </button>

          <div className="mb-12">
            <h1 className="font-serif text-3xl text-gray-900 mb-2">Checkout</h1>
            <p className="font-sans text-gray-400 text-sm">Please enter your details below.</p>
          </div>

          <form onSubmit={handleSubmit} className="flex flex-col gap-10">

            {/* Contact */}
            <section>
              <h2 className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 mb-6">Contact Information</h2>
              <div className="flex flex-col gap-6">
                <input 
                  type="email" 
                  placeholder="Email Address" 
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors"
                />
                <input 
                  type="tel" 
                  placeholder="Phone Number (e.g. +60123456789)" 
                  required
                  value={phone}
                  onChange={(e) => setPhone(e.target.value)}
                  className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors"
                />
              </div>
            </section>

            {/* Shipping */}
            <section>
              <h2 className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 mb-6">Shipping Address</h2>
              <div className="grid grid-cols-2 gap-6 mb-6">
                <input 
                  type="text" placeholder="First Name" required 
                  value={firstName} onChange={e => setFirstName(e.target.value)}
                  className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                />
                <input 
                  type="text" placeholder="Last Name" required 
                  value={lastName} onChange={e => setLastName(e.target.value)}
                  className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                />
              </div>
              <div className="flex flex-col gap-6">
                <input 
                  type="text" placeholder="Address" required 
                  value={address} onChange={e => setAddress(e.target.value)}
                  className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                />
                <input type="text" placeholder="Apartment, suite, etc. (optional)" className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" />
                <div className="grid grid-cols-2 gap-6">
                   <input 
                    type="text" placeholder="Postcode" required 
                    value={postcode} onChange={e => setPostcode(e.target.value)}
                    className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                   />
                   <input 
                    type="text" placeholder="City" required 
                    value={city} onChange={e => setCity(e.target.value)}
                    className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                   />
                </div>

                {/* Region Selection for Shipping Calc */}
                <div className="relative">
                  <select 
                    value={region}
                    onChange={(e) => setRegion(e.target.value as 'west' | 'east')}
                    className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 transition-colors appearance-none cursor-pointer"
                  >
                    <option value="west">West Malaysia (Peninsular)</option>
                    <option value="east">East Malaysia (Sabah & Sarawak)</option>
                  </select>
                  <div className="absolute right-0 top-1/2 -translate-y-1/2 pointer-events-none opacity-50">
                    <svg width="10" height="6" viewBox="0 0 10 6" fill="currentColor">
                       <path d="M5 6L0 0H10L5 6Z" />
                    </svg>
                  </div>
                </div>

                <input type="text" placeholder="Country" defaultValue="Malaysia" disabled className="w-full py-3 bg-transparent border-b border-brand-latte/40 text-gray-400 cursor-not-allowed font-sans" />
              </div>
            </section>

            {/* Voucher Section */}
            <section>
              <h2 className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 mb-6 flex items-center gap-2">
                 <Tag size={14} className="text-gray-400" /> Voucher
              </h2>

              <div className="relative">
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    placeholder="Enter voucher code" 
                    value={voucherCode}
                    onChange={(e) => setVoucherCode(e.target.value)}
                    disabled={isFreeShipping}
                    className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed" 
                  />
                  {isFreeShipping ? (
                    <button 
                      type="button" 
                      onClick={handleRemoveVoucher}
                      className="text-gray-400 hover:text-red-400 transition-colors px-4 border-b border-brand-latte/40"
                    >
                      <X size={18} />
                    </button>
                  ) : (
                    <button 
                      type="button" 
                      onClick={handleApplyVoucher}
                      className="bg-gray-900 text-white px-6 py-2 text-[10px] font-bold uppercase tracking-widest hover:bg-brand-flamingo transition-colors rounded-[2px]"
                    >
                      Apply
                    </button>
                  )}
                </div>

                {voucherMessage && (
                  <p className={`text-xs mt-2 flex items-center gap-1 ${voucherMessage.type === 'success' ? 'text-green-600' : 'text-red-500'}`}>
                    {voucherMessage.type === 'success' ? <CheckCircle size={12} /> : <AlertTriangle size={12} />}
                    {voucherMessage.text}
                  </p>
                )}
              </div>
            </section>

            {/* Payment Info */}
            <section>
              <h2 className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 mb-6">Payment Method</h2>
              <div className="bg-brand-grey/5 p-6 rounded-[2px] border border-brand-latte/10">
                <div className="flex flex-col gap-4 items-center justify-center py-4 text-center">
                  <Lock size={24} className="text-brand-latte mb-2" />
                  <p className="text-sm text-gray-500 font-light">
                    You will be redirected to <span className="font-bold text-gray-900">CHIP</span> to securely complete your payment.
                  </p>
                  <div className="flex items-center gap-2 text-[10px] text-gray-400 uppercase tracking-widest mt-2">
                    <CreditCard size={12} /> Secure Gateway
                  </div>
                </div>
              </div>
            </section>

            {error && (
              <div className="bg-red-50 p-4 rounded border border-red-100 flex items-start gap-3">
                <AlertTriangle className="text-red-500 flex-shrink-0 mt-0.5" size={16} />
                <div className="flex-1">
                  <p className="text-red-600 text-sm font-bold mb-1">Payment Initialization Failed</p>
                  <p className="text-red-500 text-xs">{error}</p>
                  {(error.includes("Configuration") || error.includes("missing")) && (
                     <p className="text-red-500 text-[10px] mt-2 italic">
                       Developer Note: Ensure VITE_CHIP_ID and VITE_CHIP_API are set in Vercel and the app has been redeployed.
                     </p>
                  )}
                </div>
              </div>
            )}

            <button 
                type="submit"
                disabled={isProcessing}
                className="mt-4 w-full bg-brand-flamingo text-white h-14 rounded-full flex items-center justify-center gap-3 hover:bg-brand-gold transition-colors font-sans text-[11px] uppercase tracking-[0.2em] font-bold shadow-lg shadow-brand-flamingo/20 disabled:opacity-70 disabled:cursor-wait"
              >
                {isProcessing ? (
                  <>
                    <Loader2 size={16} className="animate-spin" /> Redirecting to CHIP...
                  </>
                ) : (
                  `Pay RM ${total}`
                )}
            </button>

          </form>
        </div>
      </div>

      {/* Right Column: Summary */}
      <div className="w-full lg:w-[42%] bg-brand-grey/5 px-6 lg:px-16 pt-12 lg:pt-24 pb-12 lg:min-h-screen border-l border-brand-latte/10">
        <div className="max-w-md mx-auto lg:mx-0 sticky top-24">
          <h2 className="font-serif text-2xl text-gray-900 mb-8">In Your Bag</h2>

          <div className="space-y-6 mb-8">
            {cart.map(item => (
              <div key={item.id} className="flex gap-4 items-start">
                 <div className="w-16 h-20 bg-white border border-brand-latte/20 relative rounded-[2px] overflow-hidden">
                    <img src={item.image} className="w-full h-full object-cover" />
                    <span className="absolute -top-0 -right-0 w-5 h-5 bg-brand-latte/90 text-white text-[10px] font-bold flex items-center justify-center rounded-bl-lg">
                      {item.quantity}
                    </span>
                 </div>
                 <div className="flex-1">
                   <h4 className="font-serif text-gray-900">{item.name}</h4>
                   <p className="text-xs text-gray-500 font-sans mt-1">RM {item.price}</p>
                 </div>
                 <div className="font-sans text-sm font-bold text-gray-900">
                   RM {item.price * item.quantity}
                 </div>
              </div>
            ))}
          </div>

          {/* Complimentary Touches - Checkout Version */}
          <div className="bg-white border border-brand-latte/20 p-5 rounded-[2px] mb-8">
            <h4 className="font-sans text-[10px] font-bold uppercase tracking-widest text-brand-gold mb-3 flex items-center gap-2">
              <Sparkles size={12} /> The Unboxing Experience
            </h4>
            <div className="space-y-3">
              <div className="flex items-center gap-3">
                  <div className="w-8 h-8 rounded-full bg-brand-grey/10 flex items-center justify-center text-gray-400">
                      <Gift size={14} />
                  </div>
                  <div>
                    <p className="font-serif text-sm text-gray-900">Signature Keepsake Box</p>
                    <p className="font-sans text-[9px] text-gray-400 uppercase tracking-wider">Included</p>
                  </div>
              </div>
              <div className="flex items-center gap-3">
                  <div className="w-8 h-8 rounded-full bg-brand-grey/10 flex items-center justify-center text-gray-400">
                      <Feather size={14} />
                  </div>
                  <div>
                    <p className="font-serif text-sm text-gray-900">Handwritten Gift Note</p>
                    <p className="font-sans text-[9px] text-gray-400 uppercase tracking-wider">Included</p>
                  </div>
              </div>
            </div>
          </div>

          <div className="border-t border-brand-latte/20 pt-6 space-y-3">
             <div className="flex justify-between text-sm font-sans text-gray-600">
                <span>Subtotal</span>
                <span>RM {subtotal}</span>
             </div>
             <div className="flex justify-between text-sm font-sans text-gray-600 items-center">
                <span>Shipping</span>
                {isFreeShipping ? (
                  <span className="text-brand-green font-bold text-xs uppercase tracking-wider flex items-center gap-1">
                    <Tag size={10} /> Free
                  </span>
                ) : (
                  <span>RM {shipping}</span>
                )}
             </div>

             {/* Shipping Note */}
             {!isFreeShipping && (
               <div className="text-[10px] text-gray-400 italic text-right">
                 {region === 'west' 
                   ? (totalItems >= 3 ? '(West Malaysia Bulk Rate)' : '(West Malaysia Standard Rate)') 
                   : '(East Malaysia Rate)'}
               </div>
             )}

             {/* Applied Voucher Note */}
             {isFreeShipping && (
                <div className="text-[10px] text-brand-green italic text-right">
                  Code SHIPFREE88 applied
                </div>
             )}
          </div>

          <div className="border-t border-brand-latte/20 pt-6 mt-6">
             <div className="flex justify-between items-end">
                <span className="font-serif text-xl text-gray-900">Total</span>
                <span className="font-serif text-3xl text-gray-900">RM {total}</span>
             </div>
          </div>

          <div className="mt-12 flex items-center gap-3 justify-center text-brand-gold opacity-60">
             <CheckCircle size={14} />
             <span className="text-[10px] uppercase tracking-widest font-bold">Secure Payment Processing</span>
          </div>

        </div>
      </div>

    </div>
  );
};

export interface Product {
  id: string;
  name: string;
  price: number;
  description: string;
  image: string;
  additionalImages?: string[];
  badge?: string;
  material?: string;
  care?: string;
  collection?: string;
  size?: string;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface SiteConfig {
  heroImage: string;
}

export interface Order {
  id: string;
  customerName: string;
  customerEmail: string;
  customerPhone: string;
  items: CartItem[];
  total: number;
  status: 'pending' | 'paid' | 'shipped' | 'delivered' | 'failed' | 'cancelled';
  date: string;
  shippingAddress: string;
  isGift?: boolean;
  giftTo?: string;
  giftFrom?: string;
}

export interface Subscriber {
  id: string;
  email: string;
  date: string;
}

import React, { useState, useEffect } from 'react';
import { CartItem } from '../types';
import { Lock, CheckCircle, ArrowLeft, Loader2, CreditCard, AlertTriangle, Tag, X, Gift, PenTool, Check, Sparkles } from 'lucide-react';
import { createOrderInDb } from '../firebase';
import { useNavigate } from 'react-router-dom';

interface CheckoutViewProps {
  cart: CartItem[];
  onOrderSuccess: () => void;
}

// We use the local proxy path now (configured in vite.config.ts and vercel.json)
// This avoids CORS errors by letting the server handle the cross-origin request
const API_URL = '/api/chip/purchases/';

export const CheckoutView: React.FC<CheckoutViewProps> = ({ cart, onOrderSuccess }) => {
  const navigate = useNavigate();
  const subtotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalItems = cart.reduce((sum, item) => sum + item.quantity, 0);

  // Packaging Logic
  const packagingCount = Math.ceil(totalItems / 2);

  // Shipping State
  const [region, setRegion] = useState<'west' | 'east'>('west');

  // Voucher State
  const [voucherCode, setVoucherCode] = useState('');
  const [isFreeShipping, setIsFreeShipping] = useState(false);
  const [voucherMessage, setVoucherMessage] = useState<{type: 'success' | 'error', text: string} | null>(null);

  // Gift State
  const [isGift, setIsGift] = useState(false);
  const [giftTo, setGiftTo] = useState('');
  const [giftFrom, setGiftFrom] = useState('');

  // Shipping Logic
  // West Malaysia: RM 8 flat, or RM 10 if 3+ items
  // East Malaysia: RM 12 flat
  const calculateShipping = () => {
    if (isFreeShipping) return 0;

    if (region === 'east') {
      return 12;
    } else {
      return totalItems >= 3 ? 10 : 8;
    }
  };

  const shipping = calculateShipping();
  const total = subtotal + shipping;

  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState('');

  // Form State
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [address, setAddress] = useState('');
  const [postcode, setPostcode] = useState('');
  const [city, setCity] = useState('');

  // Access Environment Variables Directly
  const getPaymentConfig = () => {
    const env = (import.meta as any).env;
    return {
      // Try VITE_ prefix first (Standard), then CHIP_ prefix
      brandId: env.VITE_CHIP_ID || env.CHIP_ID,
      apiKey: env.VITE_CHIP_API || env.CHIP_API
    };
  };

  useEffect(() => {
    const { brandId, apiKey } = getPaymentConfig();
    if (!brandId || !apiKey) {
      console.warn("[Payment Config] Missing keys.");
    }
  }, []);

  const handleApplyVoucher = (e: React.MouseEvent) => {
    e.preventDefault();
    setVoucherMessage(null);

    const code = voucherCode.trim().toUpperCase();

    if (!code) return;

    if (code === 'SHIPFREE88') {
      setIsFreeShipping(true);
      setVoucherMessage({ type: 'success', text: 'Free shipping applied!' });
    } else {
      setIsFreeShipping(false);
      setVoucherMessage({ type: 'error', text: 'Invalid voucher code.' });
    }
  };

  const handleRemoveVoucher = () => {
    setVoucherCode('');
    setIsFreeShipping(false);
    setVoucherMessage(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);
    setError('');

    const { brandId, apiKey } = getPaymentConfig();

    if (!brandId || !apiKey) {
      setError("Configuration Error: Payment Gateway ID or API Key is missing.");
      setIsProcessing(false);
      return;
    }

    try {
      // 1. Create Order in Database first (status pending)
      const orderRef = await createOrderInDb({
        customerName: `${firstName} ${lastName}`,
        customerEmail: email,
        customerPhone: phone,
        items: cart,
        total: total,
        status: 'pending',
        date: new Date().toISOString(),
        shippingAddress: `${address}, ${postcode} ${city}, ${region === 'east' ? 'East Malaysia' : 'West Malaysia'}`,
        isGift: isGift,
        giftTo: isGift ? giftTo : undefined,
        giftFrom: isGift ? giftFrom : undefined
      });

      // 2. Prepare Chip Payload
      // Note: Amounts must be in cents (integer)
      const payload = {
        brand_id: brandId,
        client: {
          email: email,
          phone: phone, 
          full_name: `${firstName} ${lastName}`.substring(0, 30), // Chip limit
        },
        purchase: {
          currency: 'MYR',
          products: [
            ...cart.map(item => ({
              name: item.name.substring(0, 256),
              quantity: item.quantity,
              price: Math.round(item.price * 100) // Chip expects cents
            })),
            {
              name: isFreeShipping ? "Shipping Fee (Waived)" : "Shipping Fee",
              quantity: 1,
              price: Math.round(shipping * 100)
            }
          ]
        },
        reference: orderRef.id,
        // We pass the order ID in the redirect URL so we can update it later
        success_redirect: `${window.location.origin}/#/payment/callback?result=success&order=${orderRef.id}`,
        failure_redirect: `${window.location.origin}/#/payment/callback?result=failed&order=${orderRef.id}`,
        cancel_redirect: `${window.location.origin}/#/payment/callback?result=cancelled&order=${orderRef.id}`,
      };

      // 3. Call Chip API via Proxy
      const response = await fetch(API_URL, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiKey}`
        },
        body: JSON.stringify(payload)
      });

      let data;
      try {
        data = await response.json();
      } catch (jsonError) {
        throw new Error(`Invalid response from payment provider: ${response.statusText}`);
      }

      if (!response.ok) {
        console.error("Chip API Error Response:", data);
        const msg = data.message || (data.errors ? Object.values(data.errors).join(', ') : "Payment initialization failed");
        throw new Error(msg);
      }

      onOrderSuccess(); 

      if (data.checkout_url) {
        window.location.href = data.checkout_url;
      } else {
        throw new Error("No checkout URL returned from payment provider");
      }

    } catch (err: any) {
      console.error("Payment Error:", err);
      setError(err.message || "Failed to initiate payment. Please try again.");
      setIsProcessing(false);
    }
  };

  return (
    <div className="min-h-screen bg-white animate-fade-in flex flex-col lg:flex-row">

      {/* Left Column: Form */}
      <div className="w-full lg:w-[58%] px-6 lg:px-24 pt-12 lg:pt-24 pb-12 border-r border-brand-latte/10">
        <div className="max-w-xl mx-auto lg:mx-0">

          <button onClick={() => navigate('/cart')} className="flex items-center gap-2 text-gray-400 hover:text-brand-flamingo mb-10 transition-colors text-xs font-bold uppercase tracking-widest">
            <ArrowLeft size={14} /> Back to Bag
          </button>

          <div className="mb-12">
            <h1 className="font-serif text-3xl text-gray-900 mb-2">Checkout</h1>
            <p className="font-sans text-gray-400 text-sm">Please enter your details below.</p>
          </div>

          <form onSubmit={handleSubmit} className="flex flex-col gap-10">

            {/* Contact */}
            <section>
              <h2 className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 mb-6">Contact Information</h2>
              <div className="flex flex-col gap-6">
                <input 
                  type="email" 
                  placeholder="Email Address" 
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors"
                />
                <input 
                  type="tel" 
                  placeholder="Phone Number (e.g. +60123456789)" 
                  required
                  value={phone}
                  onChange={(e) => setPhone(e.target.value)}
                  className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors"
                />
              </div>
            </section>

            {/* Shipping */}
            <section>
              <h2 className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 mb-6">Shipping Address</h2>
              <div className="grid grid-cols-2 gap-6 mb-6">
                <input 
                  type="text" placeholder="First Name" required 
                  value={firstName} onChange={e => setFirstName(e.target.value)}
                  className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                />
                <input 
                  type="text" placeholder="Last Name" required 
                  value={lastName} onChange={e => setLastName(e.target.value)}
                  className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                />
              </div>
              <div className="flex flex-col gap-6">
                <input 
                  type="text" placeholder="Address" required 
                  value={address} onChange={e => setAddress(e.target.value)}
                  className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                />
                <input type="text" placeholder="Apartment, suite, etc. (optional)" className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" />
                <div className="grid grid-cols-2 gap-6">
                   <input 
                    type="text" placeholder="Postcode" required 
                    value={postcode} onChange={e => setPostcode(e.target.value)}
                    className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                   />
                   <input 
                    type="text" placeholder="City" required 
                    value={city} onChange={e => setCity(e.target.value)}
                    className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors" 
                   />
                </div>

                {/* Region Selection for Shipping Calc */}
                <div className="relative">
                  <select 
                    value={region}
                    onChange={(e) => setRegion(e.target.value as 'west' | 'east')}
                    className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 transition-colors appearance-none cursor-pointer"
                  >
                    <option value="west">West Malaysia (Peninsular)</option>
                    <option value="east">East Malaysia (Sabah & Sarawak)</option>
                  </select>
                  <div className="absolute right-0 top-1/2 -translate-y-1/2 pointer-events-none opacity-50">
                    <svg width="10" height="6" viewBox="0 0 10 6" fill="currentColor">
                       <path d="M5 6L0 0H10L5 6Z" />
                    </svg>
                  </div>
                </div>

                <input type="text" placeholder="Country" defaultValue="Malaysia" disabled className="w-full py-3 bg-transparent border-b border-brand-latte/40 text-gray-400 cursor-not-allowed font-sans" />
              </div>
            </section>

            {/* Gift Options - New Section */}
            <section className="bg-brand-grey/5 p-6 rounded-[2px] border border-brand-latte/10">
              <div className="flex items-center gap-3 mb-4">
                 <input 
                    id="isGift"
                    type="checkbox"
                    checked={isGift}
                    onChange={(e) => setIsGift(e.target.checked)}
                    className="w-4 h-4 text-brand-flamingo rounded border-gray-300 focus:ring-brand-flamingo"
                 />
                 <label htmlFor="isGift" className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 cursor-pointer select-none">
                   Would you like us to write on the card?
                 </label>
              </div>

              <div className={`grid grid-cols-2 gap-6 transition-all duration-500 overflow-hidden ${isGift ? 'max-h-40 opacity-100 mt-4' : 'max-h-0 opacity-0'}`}>
                <div className="col-span-1">
                   <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-2">To</label>
                   <input 
                     type="text" 
                     placeholder="Recipient Name"
                     value={giftTo}
                     onChange={(e) => setGiftTo(e.target.value)}
                     className="w-full bg-white border-b border-brand-latte/40 px-3 py-2 font-serif text-gray-800 focus:outline-none focus:border-brand-flamingo"
                   />
                </div>
                <div className="col-span-1">
                   <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-2">From</label>
                   <input 
                     type="text" 
                     placeholder="Sender Name"
                     value={giftFrom}
                     onChange={(e) => setGiftFrom(e.target.value)}
                     className="w-full bg-white border-b border-brand-latte/40 px-3 py-2 font-serif text-gray-800 focus:outline-none focus:border-brand-flamingo"
                   />
                </div>
                <p className="col-span-2 text-[10px] text-gray-400 italic">
                   We will handwrite these names on your complimentary card.
                </p>
              </div>
            </section>

            {/* Voucher Section */}
            <section>
              <h2 className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 mb-6 flex items-center gap-2">
                 <Tag size={14} className="text-gray-400" /> Voucher
              </h2>

              <div className="relative">
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    placeholder="Enter voucher code" 
                    value={voucherCode}
                    onChange={(e) => setVoucherCode(e.target.value)}
                    disabled={isFreeShipping}
                    className="w-full py-3 bg-transparent border-b border-brand-latte/40 focus:border-brand-flamingo outline-none font-sans text-gray-800 placeholder:text-gray-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed" 
                  />
                  {isFreeShipping ? (
                    <button 
                      type="button" 
                      onClick={handleRemoveVoucher}
                      className="text-gray-400 hover:text-red-400 transition-colors px-4 border-b border-brand-latte/40"
                    >
                      <X size={18} />
                    </button>
                  ) : (
                    <button 
                      type="button" 
                      onClick={handleApplyVoucher}
                      className="bg-gray-900 text-white px-6 py-2 text-[10px] font-bold uppercase tracking-widest hover:bg-brand-flamingo transition-colors rounded-[2px]"
                    >
                      Apply
                    </button>
                  )}
                </div>

                {voucherMessage && (
                  <p className={`text-xs mt-2 flex items-center gap-1 ${voucherMessage.type === 'success' ? 'text-green-600' : 'text-red-500'}`}>
                    {voucherMessage.type === 'success' ? <CheckCircle size={12} /> : <AlertTriangle size={12} />}
                    {voucherMessage.text}
                  </p>
                )}
              </div>
            </section>

            {/* Payment Info */}
            <section>
              <h2 className="font-sans text-xs font-bold uppercase tracking-widest text-gray-900 mb-6">Payment Method</h2>
              <div className="bg-brand-grey/5 p-6 rounded-[2px] border border-brand-latte/10">
                <div className="flex flex-col gap-4 items-center justify-center py-4 text-center">
                  <Lock size={24} className="text-brand-latte mb-2" />
                  <p className="text-sm text-gray-500 font-light">
                    You will be redirected to <span className="font-bold text-gray-900">CHIP</span> to securely complete your payment.
                  </p>
                  <div className="flex items-center gap-2 text-[10px] text-gray-400 uppercase tracking-widest mt-2">
                    <CreditCard size={12} /> Secure Gateway
                  </div>
                </div>
              </div>
            </section>

            {error && (
              <div className="bg-red-50 p-4 rounded border border-red-100 flex items-start gap-3">
                <AlertTriangle className="text-red-500 flex-shrink-0 mt-0.5" size={16} />
                <div className="flex-1">
                  <p className="text-red-600 text-sm font-bold mb-1">Payment Initialization Failed</p>
                  <p className="text-red-500 text-xs">{error}</p>
                  {(error.includes("Configuration") || error.includes("missing")) && (
                     <p className="text-red-500 text-[10px] mt-2 italic">
                       Developer Note: Ensure VITE_CHIP_ID and VITE_CHIP_API are set in Vercel and the app has been redeployed.
                     </p>
                  )}
                </div>
              </div>
            )}

            <button 
                type="submit"
                disabled={isProcessing}
                className="mt-4 w-full bg-brand-flamingo text-white h-14 rounded-full flex items-center justify-center gap-3 hover:bg-brand-gold transition-colors font-sans text-[11px] uppercase tracking-[0.2em] font-bold shadow-lg shadow-brand-flamingo/20 disabled:opacity-70 disabled:cursor-wait"
              >
                {isProcessing ? (
                  <>
                    <Loader2 size={16} className="animate-spin" /> Redirecting to CHIP...
                  </>
                ) : (
                  `Pay RM ${total}`
                )}
            </button>

          </form>
        </div>
      </div>

      {/* Right Column: Summary */}
      <div className="w-full lg:w-[42%] bg-brand-grey/5 px-6 lg:px-16 pt-12 lg:pt-24 pb-12 lg:min-h-screen border-l border-brand-latte/10">
        <div className="max-w-md mx-auto lg:mx-0 sticky top-24">
          <h2 className="font-serif text-2xl text-gray-900 mb-8">In Your Bag</h2>

          <div className="space-y-6 mb-8">
            {cart.map(item => (
              <div key={item.id} className="flex gap-4 items-start">
                 <div className="w-16 h-20 bg-white border border-brand-latte/20 relative rounded-[2px] overflow-hidden">
                    <img src={item.image} className="w-full h-full object-cover" />
                    <span className="absolute -top-0 -right-0 w-5 h-5 bg-brand-latte/90 text-white text-[10px] font-bold flex items-center justify-center rounded-bl-lg">
                      {item.quantity}
                    </span>
                 </div>
                 <div className="flex-1">
                   <h4 className="font-serif text-gray-900">{item.name}</h4>
                   <p className="text-xs text-gray-500 font-sans mt-1">RM {item.price}</p>
                 </div>
                 <div className="font-sans text-sm font-bold text-gray-900">
                   RM {item.price * item.quantity}
                 </div>
              </div>
            ))}
          </div>

          {/* Complimentary Touches - Checkout Version */}
          <div className="bg-white border border-brand-latte/20 p-5 rounded-[2px] mb-8">
            <h4 className="font-sans text-[10px] font-bold uppercase tracking-widest text-brand-gold mb-3 flex items-center gap-2">
              <Sparkles size={12} /> The Unboxing Experience
            </h4>
            <div className="space-y-3">
              {/* Box */}
              <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                      <div className="w-6 h-6 rounded-full bg-brand-gold text-white text-[10px] font-bold flex items-center justify-center">
                          {packagingCount}
                      </div>
                      <div className="w-8 h-8 rounded-full bg-brand-grey/10 flex items-center justify-center text-gray-400">
                          <Gift size={14} />
                      </div>
                      <div>
                        <p className="font-serif text-sm text-gray-900">Signature Keepsake Box</p>
                      </div>
                  </div>
                  <Check size={14} className="text-brand-green" strokeWidth={2.5} />
              </div>

              {/* Card */}
              <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                      <div className="w-6 h-6 rounded-full bg-brand-gold text-white text-[10px] font-bold flex items-center justify-center">
                          {packagingCount}
                      </div>
                      <div className="w-8 h-8 rounded-full bg-brand-grey/10 flex items-center justify-center text-gray-400">
                          <PenTool size={14} />
                      </div>
                      <div>
                        <p className="font-serif text-sm text-gray-900">To & From Card</p>
                      </div>
                  </div>
                  <Check size={14} className="text-brand-green" strokeWidth={2.5} />
              </div>
            </div>
          </div>

          <div className="border-t border-brand-latte/20 pt-6 space-y-3">
             <div className="flex justify-between text-sm font-sans text-gray-600">
