                       Open Console <ExternalLink size={10} />
                     </a>
                   </div>
                 </div>

                 <div className="flex gap-4">
                   <div className="w-8 h-8 rounded-full bg-brand-latte/20 flex items-center justify-center font-bold text-gray-600 flex-shrink-0">2</div>
                   <div>
